from flask import Flask, request, redirect, session, url_for, jsonify
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Client configuration
client_config = {
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'domain': 'your_domain.com',  # e.g., 'example.com'
    'authorization_endpoint': 'https://oauth.example.com/authorize',
    'token_endpoint': 'https://oauth.example.com/token',
    'redirect_uri': '/callback'  # This is the relative path
}

oauth = OAuth(app)
oauth.register(
    name='oauth_provider',
    client_id=client_config['client_id'],
    client_secret=client_config['client_secret'],
    authorization_base_url=client_config['authorization_endpoint'],
    token_url=client_config['token_endpoint'],
)

@app.route('/')
def index():
    redirect_uri = url_for('authorize', _external=True)
    session['redirect_uri'] = redirect_uri
    return f'Go to <a href="/login">/login</a>'

@app.route('/login')
def login():
    redirect_uri = session.get('redirect_uri')
    if not redirect_uri:
        return 'Redirect URI not set in session', 400

    # Validate redirect_uri
    if client_config['domain'] not in redirect_uri:
        return f'Redirect URI {redirect_uri} does not contain domain {client_config["domain"]}', 403

    authorization_redirect = oauth.oauth_provider.authorize_redirect(
        request, redirect_uri
    )
    return authorization_redirect

@app.route('/callback')
def authorize():
    token = oauth.oauth_provider.authorize_access_token()
    session['oauth_token'] = token

    # You can now use the access token to make API calls or fetch user data
    return jsonify(token)

